 1	import * as React from 'react';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	  ValidatedOptions,
 8	} from '@patternfly/react-core';
 9	import { useField } from 'formik';
10	import { BaseInputFieldProps } from './types';
11	import { useFormikValidationFix } from './formik-validation-fix';
12	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
13	import { getFieldId } from './utils';
14	
15	const BaseInputField: React.FC<
16	  BaseInputFieldProps & {
17	    children: (props) => React.ReactNode;
18	  }
19	> = ({
20	  label,
21	  helpText,
22	  required,
23	  children,
24	  name,
25	  onChange,
26	  onBlur,
27	  helpTextInvalid,
28	  validated,
29	  ...props
30	}) => {
31	  const [field, { touched, error }] = useField({ name, type: 'input' });
32	  const fieldId = getFieldId(name, 'input');
33	  const isValid = !(touched && error);
34	  const errorMessage = !isValid ? error : '';
35	  useFormikValidationFix(field.value);
36	
37	  return (
38	    <FormGroup fieldId={fieldId} label={label} isRequired={required}>
39	      {children({
40	        ...field,
41	        ...props,
42	        value: field.value || '',
43	        id: fieldId,
44	        label,
45	        validated: !isValid ? ValidatedOptions.error : validated,
46	        'aria-describedby': helpText ? `${fieldId}-helper` : undefined,
47	        onChange: (event) => {
48	          field.onChange(event);
49	          onChange && onChange(event);
50	        },
51	        onBlur: (event) => {
52	          field.onBlur(event);
53	          onBlur && onBlur(event);
54	        },
55	      })}
56	
57	      <FormHelperText id={`${fieldId}-helper`}>
58	        <HelperText>
59	          {!isValid ? (
60	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
61	              {errorMessage || helpTextInvalid}
62	            </HelperTextItem>
63	          ) : (
64	            <HelperTextItem variant={validated}>{helpText}</HelperTextItem>
65	          )}
66	        </HelperText>
67	      </FormHelperText>
68	    </FormGroup>
69	  );
70	};
71	
72	export default BaseInputField;

